var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나는 한때 관리국 소속이었다.","JPN":"私は昔、管理局に所属していた。","ENG":"I used to be part of the Administration.","TWN":"我曾經是管理局的一員。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"내가 아는 그 관리국 말이야?","JPN":"私の知ってる、あの管理局？","ENG":"Is it the Administration that I know?","TWN":"你說的是我所知道的那個管理局嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아마도 그렇겠지.","JPN":"おそらくな。","ENG":"Yes, probably.","TWN":"大概是吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"지금도 그때와 같은 관리국이라 부를 수 있을진 모르겠지만.","JPN":"今の管理局を、あの時と同じ管理局と呼べるかは分からないが。","ENG":"Though I'm not sure if it can still be called the same Administration as before.","TWN":"雖然不知道現在是否還能稱作是當時的管理局。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리가 처음 만났을 때, 그대에겐 찾는 사람이 있다고 했었지.","JPN":"初対面の時、そなたは人を探していると言っていたな。","ENG":"When we first met, you said you were looking for someone.","TWN":"我們第一次見面時，你說過你在找一個人。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그건… 버려진 형제들의 타깃인 날 말하는 거였나?","JPN":"そなたが探していたのは捨てられた兄弟のターゲット……某のことだったのか。","ENG":"Was that… me? The one the Brothers Abandoned was targeting?","TWN":"那個人…就是我嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"맞아.","JPN":"そうだ。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"하지만 내가 찾는 건 당신만이 아니었어.","JPN":"しかし私が探していたのはお前だけじゃない。","ENG":"But you weren't the only one I was after.","TWN":"但我並非只找你。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신과 연결점이 있는 다른 사람을 찾고 싶었거든.","JPN":"もう一人、お前と関わりのある人を探していたんだ。","ENG":"I was looking for someone connected to you.","TWN":"我想找一個與你有關的另一個人。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나와 연결점이 있다면… 그 사람도 관리국 출신인가?","JPN":"某と関わりのある者……その者も管理局出身なのか？","ENG":"Someone who's connected to me… Is that individual also from the Administration?","TWN":"和我有關…那個人也是管理局出身嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아마도 내 아버지일 거다.","JPN":"多分、私の父親だろう。","ENG":"Most likely… my father.","TWN":"可能是我父親。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아마도 아버지일 거라니… 찾고 있는 사람이 누구인지도 모르는 거야?","JPN":"多分って……探している人が誰なのかも分からないの？","ENG":"\\"Most likely,\\" you say… You don't even know who you're looking for?","TWN":"什麼叫可能是你父親…你連要找的人是誰都不知道嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나도 네 사부와 마찬가지로 과거에 대한 기억이 대부분 날아갔거든.","JPN":"私もお前の師匠と同じく、過去の記憶をほとんど失っているからな。","ENG":"Just like your master, I lost most of my memories.","TWN":"我也和你師父一樣，大部分過去的記憶都消失了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그렇게 된 직후엔 한동안 방황하기도 했었지.","JPN":"記憶を失った直後はしばらくの間彷徨いもした。","ENG":"I felt lost for a while right after it happened.","TWN":"在那之後，有一段時間我一直在四處遊蕩。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"관리국을 떠나면서 기억소거 시술을 받은 건가?","JPN":"管理局を去る時、記憶消去手術を受けたのか。","ENG":"Did they wipe your memory when you left the Administration?","TWN":"離開管理局時，接受了記憶消除手術嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"난 당신처럼 내 발로 관리국을 떠나지 않았어.","JPN":"私はお前のように自分の足で管理局を去ったわけじゃない。","ENG":"I didn't leave voluntarily like you did.","TWN":"我沒有像你一樣，主動離開管理局。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"최전선에서 큰 전투를 치른 뒤로… 기억의 대부분을 잃었거든.","JPN":"最前線で大規模の戦闘を経験し……記憶の大半を失った。","ENG":"After a major battle on the front lines… I lost most of my memories.","TWN":"在一次前線的大規模作戰後…我失去了大部分記憶。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"가까스로 살아 돌아왔지만, 관리국은 날 없는 사람 취급하더군.","JPN":"なんとか生還したものの、管理局で私は存在しない人間となっていた。","ENG":"I barely made it back alive, but the Administration acted like I didn't exist.","TWN":"好不容易活著回來，但管理局卻把我當成不存在的人。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇다면 그대는 어쩌다 관리국에 반목하는 자들과 함께하게 된 것이지?","JPN":"では、どういう経緯で管理局に敵対する集団と行動を共にすることになったのだ？","ENG":"So why did you end up working with a group opposing the Administration?","TWN":"那你為什麼會和一個反對管理局的團體在一起？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그쪽에서 먼저 연락책을 보냈어.","JPN":"あっちから連絡係を送って来たんだ。","ENG":"They approached me first.","TWN":"他們先派人聯繫了我。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"자길 도와주면 내 아버지의 행방을 찾도록 도와주겠다면서 말이야","JPN":"自分たちに協力したら、父の行方を探すのを手伝うと言ってな。","ENG":"Said if I helped them, they'd help me find my father.","TWN":"說只要我幫助他們，他們就會幫我尋找我父親的下落。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼, 그 조직이 사람을 해치는 나쁜 조직이란 걸 다 알면서도 도왔던 거야?","JPN":"じゃあ、その組織が人々を脅かす悪い組織だって分かった上で手伝ったの？","ENG":"So you helped them even though you knew they were bad guys?","TWN":"所以，你明明知道那個組織是會傷害人的，還是幫助了他們？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그럼에도 불구하고 따를 수밖에 없는 거다.","JPN":"分かっていても、従うしかないんだ。","ENG":"I had no choice.","TWN":"沒辦法，我只能聽命行事。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그게 버려진 형제들의 수장이 가진 힘이니까.","JPN":"それが捨てられた兄弟のリーダーの持つ力だからな。","ENG":"That's the kind of power their leader holds.","TWN":"這就是被遺棄的兄弟首領所擁有的權力。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그곳에서 일하는 조직원들은 대개 비슷한 사연을 가지고 있어.","JPN":"そこで働いている組織員は、皆似たような事情を抱えている。","ENG":"Most of the people there have similar stories.","TWN":"在那裡做事的組織成員大多都有相似的經歷。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};